                      <>
                        <Pause className="w-4 h-4" />
                        Pause
                      </>
                    )}
                  </button>
                  <button
                    onClick={handleStopTimer}
                    className="flex-1 flex items-center justify-center gap-2 px-4 py-2 bg-status-error text-white rounded font-medium hover:opacity-90 transition-opacity"
                  >
                    <Square className="w-4 h-4" />
                    Stop
                  </button>
                </>
              )}
            </div>
          </div>

          {/* Recent Entries List */}
          <div className="flex-1 overflow-y-auto px-3 py-2">
            <h4 className="text-xs font-semibold text-light-secondary dark:text-dark-secondary mb-2">
              Recent Entries (Last 48h)
            </h4>
            {recentEntries.length === 0 ? (
              <p className="text-xs text-light-tertiary dark:text-dark-tertiary italic">
                No entries yet. Start your first timer!
              </p>
            ) : (
              <div className="space-y-1">
                {recentEntries.map((entry) => (
                  <div
                    key={entry.id}
                    className={`${getDensityClasses()} px-2 rounded hover:bg-light-hover dark:hover:bg-dark-hover cursor-pointer transition-colors`}
                    onClick={() => handleContinueEntry(entry)}
                  >
                    <div className="flex items-start justify-between">
                      <div className="flex-1 min-w-0">
                        <p className="text-light-primary dark:text-dark-primary truncate font-medium">
                          {entry.description}
                        </p>
                        <div className="flex items-center gap-2 text-xs text-light-secondary dark:text-dark-secondary">
                          <span>
                            {formatTime(new Date(entry.startTime), timeFormat)}
                          </span>
                          {entry.endTime && (
                            <>
                              <span>-</span>
                              <span>
                                {formatTime(new Date(entry.endTime), timeFormat)}
                              </span>
                            </>
                          )}
                          <span className="font-medium">
                            ({formatDuration(entry.duration, { showSeconds: false })})
                          </span>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Mini Summary & View All Button */}
          {showMiniSummary && (
            <div className="px-3 py-3 border-t border-light-divider dark:border-dark-divider">
              <div className="flex items-center justify-between mb-2">
                <span className="text-xs font-semibold text-light-secondary dark:text-dark-secondary">
                  Today's Total:
                </span>
                <span className="text-sm font-mono font-bold text-accent-magenta dark:text-accent-cyan">
                  {formatDuration(todayTotal, { showSeconds: false })}
                </span>
              </div>
              <button
                onClick={handleViewAll}
                className="w-full px-3 py-2 text-sm bg-light-background dark:bg-dark-background border border-light-divider dark:border-dark-divider rounded hover:bg-light-hover dark:hover:bg-dark-hover text-light-primary dark:text-dark-primary font-medium transition-colors"
              >
                View All →
              </button>
            </div>
          )}
        </>
      )}
    </div>
  );
}

